INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05310', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關我國性別工作平等法之規定，下列何者錯誤？', '["受僱於僱用三十人以上雇主之受僱者，為撫育未滿三歲子女，得向雇主請求每天減少工作時間 一小時，而減少之工作時間，亦得請求報酬", "子女未滿二歲須受僱者親自哺（集）乳者，除規定之休息時間外，雇主應每日另給哺（集）乳 時間六十分鐘。其哺（集）乳時間視為工作時間", "受僱者於其家庭成員預防接種、發生嚴重之疾病或其他重大事故須親自照顧時，得請家庭照顧 假；其請假日數併入事假計算，全年以七日為限", "女性受僱者因生理日致工作有困難者，每月得請生理假一日，全年請假日數未逾三日，不併入 病假計算，其餘日數併入病假計算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05311', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '志願服務者，在下列何種情形下，得檢具證明文件向地方主管機關申請核發志願服務榮譽卡？', '["志工服務年資滿三年，服務時數達三百小時以上者", "志工服務年資滿兩年，服務時數達兩百五十小時以上者", "志工服務年資滿兩年，服務時數達兩百小時以上者", "志工服務年資滿一年，服務時數達一百小時以上者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05312', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '甲乙為已婚夫婦，然甲於婚後曾多次對配偶乙暴力相向，乙雖始終認為愛情可以克服一切，因此 隱忍多年未曾報警；然甲仍不改暴力習性，乙於某次甲之暴力相向時電話報警，警方到達現場後， 甲仍對乙有暴力行為，此時警察可以採取的行為，下列何者正確？', '["警察人員發現家庭暴力罪之現行犯時，應於取得有告訴權人之同意後，才能以現行犯逕行逮捕之", "到場的警察人員可基於司法警察官或司法警察的角色，且於偵查犯罪認被告或犯罪嫌疑人犯家 庭暴力罪或違反保護令罪嫌疑重大，且有繼續侵害家庭成員生命、身體或自由之危險，且情況 急迫，因此得對甲逕行拘提", "警察人員若發現甲仍有暴力行為，而乙亦希望向警察人員報案；警察人員應請乙先到醫療機構 申請驗傷診斷書才能受理乙的報案", "因為甲為暴力現行犯，警察人員可基於司法警察官或司法警察的角色來執行拘提任務，再因為 甲是家庭暴力的現行犯，即便檢察官未到場，警察人員可以依其急迫情形為由，執行後不必另 行報請檢察官簽發拘票"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05313', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年福利與權益保障法，社會工作人員於執行業務時知悉兒童及少年有下列何種情形 時，應立即通報？', '["吸菸、飲酒、嚼檳榔", "施用毒品、非法施用管制藥品或其他有害身心健康之物質", "在道路上競駛、競技或以蛇行等危險方式駕車或參與其行為", "超過合理時間持續使用電子類產品，致有害身心健康"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05314', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據我國社會工作師法之規定，下列何者正確？', '["社會工作為助人之事業，因此社會工作師執業可不以一處為限", "社會工作師執行業務時，應撰製社會工作紀錄，其紀錄應由執業之機關（構）、團體、事務所 保存。此紀錄保存年限不得少於十年", "社會工作師及社會工作師執業處所之人員，對於因業務而知悉或持有他人之秘密，均應秉持社 工倫理之保密原則，即便面臨司法機關之詢問，可全然拒絕回答不得洩漏", "社會工作師依法執行公權力職務，有受到身體或精神上不法侵害之虞者，得請求警察機關提供 必要之協助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05315', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '低收入戶成員中有下列情形之一者，主管機關得依其原領取現金給付之金額增加補助，下列何者錯誤？', '["年滿六十五歲", "領有重大傷病證明，且經醫師評估無法工作", "懷胎滿三個月", "領有身心障礙手冊或身心障礙證明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05316', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關我國身心障礙者權益保障法對於身心障礙者之緊急保護安置的規定，下列何者錯誤？', '["身心障礙者之緊急保護安置，不得超過七十二小時；非七十二小時以上之安置，不足以保護身 心障礙者時，得聲請法院裁定繼續保護安置", "繼續保護安置以三個月為限；必要時，得聲請法院裁定延長之", "身心障礙者之緊急安置服務，得委託相關身心障礙福利機構辦理。安置期間所必要之費用，概 由各縣市政府社會局編列預算支付", "身心障礙者遭受身心障礙者權益保障法第75條各款情形之一者，情況危急非立即給予保護、 安置或其他處置，其生命、身體或自由有立即之危險或有危險之虞者，直轄市、縣（市）主管 機關應予緊急保護、安置或為其他必要之處置"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05317', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會政策的制定常受許多因素或理論所影響，下列何種理論觀點認為社會政策的制定是基於各種 利益相互競逐的狀態下而制定？', '["菁英論", "國家中心論", "多元論", "權力資源理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05318', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會救助財源籌措與給付方式，下列敘述何者正確？', '["主要財源是來自於國民所繳交的稅金", "只要申請就可以獲得給付，無需經過資產調查", "在領取給付前，要先繳交類似社會保險的保費", "領取社會救助沒有設籍與居住條件的限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05319', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會安全制度中，下列那一種制度安排，對於人民的工作誘因較強，且會強調權利與義務的對等？', '["社會救助制度", "福利服務輸送", "社會保險制度", "社會津貼給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "e0941a7e8d00", "answer_pdf_sha1": "458d61232874", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
